var ATRANS = function(object, from_entity, to_entity) {
  // Transfer is noisy — might fail
  var success = sample(Bernoulli({p: 0.9}));

  if (success) {
    return {
      from: {...from_entity, possession: from_entity.possession - object.value},
      to: {...to_entity, possession: to_entity.possession + object.value}
    };
  } else {
    // Transfer failed — states unchanged
    return {from: from_entity, to: to_entity};
  }
};

var model = Infer({method: 'MCMC'}, function() {
  // Prior: success rate unknown, could be anything
  var p_success = sample(Beta({a: 2, b: 2}));

  var ATRANS = function(obj, from, to) {
    return sample(Bernoulli({p: p_success})) ? 'success' : 'fail';
  };

  // Observe 10 transfers, 9 succeeded
  observe(Binomial({p: p_success, n: 10}), 9);

  return p_success;
});

expectation(model); // ≈ 0.85
